function filterCards(){const term=document.getElementById("searchBar").value.toLowerCase(),cards=document.querySelectorAll(".searchable-card"),noResults=document.getElementById("noResults");let visible=0;cards.forEach((card=>{const show=card.querySelector(".form-card-label").textContent.toLowerCase().includes(term);card.style.display=show?"":"none",show&&visible++})),noResults.style.display=0===visible?"block":"none"}